output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(SUBSTR(STR(?inception) , 1 , 4) AS ?year) WHERE {
  wd:Q610865 wdt:P571 ?inception .
}

args.sparql:
PREFIX math: <http://www.w3.org/2005/xpath-functions/math#>
SELECT (math:YEAR(?inception) AS ?year) WHERE {
  wd:Q610865 wdt:P571 ?inception.
}
